// Serializes query string parameters with all supported types
TEST(RestJsonServerRequestTest, RestJsonAllQueryStringTypes) {
  auto handler = std::make_shared<RecordingHandler>();
  RestJsonServer server(handler);
  smithy::http::HttpRequest request;
  request.method = "GET";
  request.target = "/AllQueryStringTypesInput?String=Hello%20there&StringList=a&StringList=b&StringList=c&StringSet=a&StringSet=b&StringSet=c&Byte=1&Short=2&Integer=3&IntegerList=1&IntegerList=2&IntegerList=3&IntegerSet=1&IntegerSet=2&IntegerSet=3&Long=4&Float=1.1&Double=1.1&DoubleList=1.1&DoubleList=2.1&DoubleList=3.1&Boolean=true&BooleanList=true&BooleanList=false&BooleanList=true&Timestamp=1970-01-01T00%3A00%3A01Z&TimestampList=1970-01-01T00%3A00%3A01Z&TimestampList=1970-01-01T00%3A00%3A02Z&TimestampList=1970-01-01T00%3A00%3A03Z&Enum=Foo&EnumList=Foo&EnumList=Baz&EnumList=Bar&IntegerEnum=1&IntegerEnumList=1&IntegerEnumList=2&IntegerEnumList=3";
  const smithy::http::HttpResponse response = server.Handler()(request);
  ASSERT_TRUE(handler->lastAllQueryStringTypes.has_value()) << response.status << " " << response.body;
  const AllQueryStringTypesInput expected = [] {
  AllQueryStringTypesInput v{};
  v.queryString = "Hello there";
  v.queryStringList = std::vector<std::string>{"a", "b", "c"};
  v.queryStringSet = std::vector<std::string>{"a", "b", "c"};
  v.queryByte = 1;
  v.queryShort = 2;
  v.queryInteger = 3;
  v.queryIntegerList = std::vector<std::int32_t>{1, 2, 3};
  v.queryIntegerSet = std::vector<std::int32_t>{1, 2, 3};
  v.queryLong = 4LL;
  v.queryFloat = 1.1F;
  v.queryDouble = 1.1;
  v.queryDoubleList = std::vector<double>{1.1, 2.1, 3.1};
  v.queryBoolean = true;
  v.queryBooleanList = std::vector<bool>{true, false, true};
  v.queryTimestamp = smithy::Timestamp::FromEpochMilliseconds(1000LL);
  v.queryTimestampList = std::vector<smithy::Timestamp>{smithy::Timestamp::FromEpochMilliseconds(1000LL), smithy::Timestamp::FromEpochMilliseconds(2000LL), smithy::Timestamp::FromEpochMilliseconds(3000LL)};
  v.queryEnum = FooEnum::FromString("Foo");
  v.queryEnumList = std::vector<FooEnum>{FooEnum::FromString("Foo"), FooEnum::FromString("Baz"), FooEnum::FromString("Bar")};
  v.queryIntegerEnum = static_cast<IntegerEnum>(1);
  v.queryIntegerEnumList = std::vector<IntegerEnum>{static_cast<IntegerEnum>(1), static_cast<IntegerEnum>(2), static_cast<IntegerEnum>(3)};
  v.queryParamsMapOfStringList = std::map<std::string, std::vector<std::string>>{{"String", std::vector<std::string>{"Hello there"}}, {"StringList", std::vector<std::string>{"a", "b", "c"}}, {"StringSet", std::vector<std::string>{"a", "b", "c"}}, {"Byte", std::vector<std::string>{"1"}}, {"Short", std::vector<std::string>{"2"}}, {"Integer", std::vector<std::string>{"3"}}, {"IntegerList", std::vector<std::string>{"1", "2", "3"}}, {"IntegerSet", std::vector<std::string>{"1", "2", "3"}}, {"Long", std::vector<std::string>{"4"}}, {"Float", std::vector<std::string>{"1.1"}}, {"Double", std::vector<std::string>{"1.1"}}, {"DoubleList", std::vector<std::string>{"1.1", "2.1", "3.1"}}, {"Boolean", std::vector<std::string>{"true"}}, {"BooleanList", std::vector<std::string>{"true", "false", "true"}}, {"Timestamp", std::vector<std::string>{"1970-01-01T00:00:01Z"}}, {"TimestampList", std::vector<std::string>{"1970-01-01T00:00:01Z", "1970-01-01T00:00:02Z", "1970-01-01T00:00:03Z"}}, {"Enum", std::vector<std::string>{"Foo"}}, {"EnumList", std::vector<std::string>{"Foo", "Baz", "Bar"}}, {"IntegerEnum", std::vector<std::string>{"1"}}, {"IntegerEnumList", std::vector<std::string>{"1", "2", "3"}}};
  return v;
}();
  EXPECT_EQ(*handler->lastAllQueryStringTypes, expected);
}

