// Handles escaping all required characters in the query string.
TEST(RestJsonServerRequestTest, RestJsonQueryStringEscaping) {
  auto handler = std::make_shared<RecordingHandler>();
  RestJsonServer server(handler);
  smithy::http::HttpRequest request;
  request.method = "GET";
  request.target = "/AllQueryStringTypesInput?String=%20%25%3A%2F%3F%23%5B%5D%40%21%24%26%27%28%29%2A%2B%2C%3B%3D%F0%9F%98%B9";
  const smithy::http::HttpResponse response = server.Handler()(request);
  ASSERT_TRUE(handler->lastAllQueryStringTypes.has_value()) << response.status << " " << response.body;
  const AllQueryStringTypesInput expected = [] {
  AllQueryStringTypesInput v{};
  v.queryString = " %:/?#[]@!$&'()*+,;=\360\237\230\271";
  v.queryParamsMapOfStringList = std::map<std::string, std::vector<std::string>>{{"String", std::vector<std::string>{" %:/?#[]@!$&'()*+,;=\360\237\230\271"}}};
  return v;
}();
  EXPECT_EQ(*handler->lastAllQueryStringTypes, expected);
}

