// Serializes document types using a list.
TEST(RestJsonServerRequestTest, DocumentInputWithList) {
  auto handler = std::make_shared<RecordingHandler>();
  RestJsonServer server(handler);
  smithy::http::HttpRequest request;
  request.method = "PUT";
  request.target = "/DocumentType";
  request.headers.Set("Content-Type", "application/json");
  request.body = "{\n    \"stringValue\": \"string\",\n    \"documentValue\": [\n        true,\n        \"hi\",\n        [\n            1,\n            2\n        ],\n        {\n            \"foo\": {\n                \"baz\": [\n                    3,\n                    4\n                ]\n            }\n        }\n    ]\n}";
  const smithy::http::HttpResponse response = server.Handler()(request);
  ASSERT_TRUE(handler->lastDocumentType.has_value()) << response.status << " " << response.body;
  const DocumentTypeInput expected = [] {
  DocumentTypeInput v{};
  v.stringValue = "string";
  v.documentValue = [] {
  smithy::DocumentList list;
  list.emplace_back(smithy::Document(true));
  list.emplace_back(smithy::Document(std::string("hi")));
  list.emplace_back([] {
  smithy::DocumentList list;
  list.emplace_back(smithy::Document(std::int64_t{1}));
  list.emplace_back(smithy::Document(std::int64_t{2}));
  return smithy::Document(std::move(list));
}());
  list.emplace_back([] {
  smithy::DocumentMap map;
  map.emplace("foo", [] {
  smithy::DocumentMap map;
  map.emplace("baz", [] {
  smithy::DocumentList list;
  list.emplace_back(smithy::Document(std::int64_t{3}));
  list.emplace_back(smithy::Document(std::int64_t{4}));
  return smithy::Document(std::move(list));
}());
  return smithy::Document(std::move(map));
}());
  return smithy::Document(std::move(map));
}());
  return smithy::Document(std::move(list));
}();
  return v;
}();
  EXPECT_EQ(*handler->lastDocumentType, expected);
}

