// Tests how timestamp request headers are serialized
TEST(RestJsonServerRequestTest, RestJsonTimestampFormatHeaders) {
  auto handler = std::make_shared<RecordingHandler>();
  RestJsonServer server(handler);
  smithy::http::HttpRequest request;
  request.method = "POST";
  request.target = "/TimestampFormatHeaders";
  request.headers.Set("X-defaultFormat", "Mon, 16 Dec 2019 23:48:18 GMT");
  request.headers.Set("X-memberDateTime", "2019-12-16T23:48:18Z");
  request.headers.Set("X-memberEpochSeconds", "1576540098");
  request.headers.Set("X-memberHttpDate", "Mon, 16 Dec 2019 23:48:18 GMT");
  request.headers.Set("X-targetDateTime", "2019-12-16T23:48:18Z");
  request.headers.Set("X-targetEpochSeconds", "1576540098");
  request.headers.Set("X-targetHttpDate", "Mon, 16 Dec 2019 23:48:18 GMT");
  const smithy::http::HttpResponse response = server.Handler()(request);
  ASSERT_TRUE(handler->lastTimestampFormatHeaders.has_value()) << response.status << " " << response.body;
  const TimestampFormatHeadersInput expected = [] {
  TimestampFormatHeadersInput v{};
  v.memberEpochSeconds = smithy::Timestamp::FromEpochMilliseconds(1576540098000LL);
  v.memberHttpDate = smithy::Timestamp::FromEpochMilliseconds(1576540098000LL);
  v.memberDateTime = smithy::Timestamp::FromEpochMilliseconds(1576540098000LL);
  v.defaultFormat = smithy::Timestamp::FromEpochMilliseconds(1576540098000LL);
  v.targetEpochSeconds = smithy::Timestamp::FromEpochMilliseconds(1576540098000LL);
  v.targetHttpDate = smithy::Timestamp::FromEpochMilliseconds(1576540098000LL);
  v.targetDateTime = smithy::Timestamp::FromEpochMilliseconds(1576540098000LL);
  return v;
}();
  EXPECT_EQ(*handler->lastTimestampFormatHeaders, expected);
}

